2. Basic Mineflayer bot

bot.js:

const mineflayer = require('mineflayer')

function createBot() {
  const bot = mineflayer.createBot({
    host: 'localhost',
    port: 25565,
    username: 'AgentBot'
  })

  bot.once('spawn', () => {
    console.log('Bot spawned in the world')
  })

  bot.on('error', console.error)
  bot.on('end', () => console.log('Bot disconnected'))

  return bot
}

module.exports = { createBot }

------------------------------
3. Add HTTP API on top

server.js:

const express = require('express')
const bodyParser = require('body-parser')
const { createBot } = require('./bot')

const app = express()
app.use(bodyParser.json())

const bot = createBot()
app.post('/move', (req, res) => {
  const { direction } = req.body
  if (direction === 'forward') bot.setControlState('forward', true)
  if (direction === 'back') bot.setControlState('back', true)
  if (direction === 'left') bot.setControlState('left', true)
  if (direction === 'right') bot.setControlState('right', true)

  setTimeout(() => {
    bot.clearControlStates()
  }, 500)

  res.json({ ok: true })
})
app.post('/chat', (req, res) => {
  const { message } = req.body
  bot.chat(message)
  res.json({ ok: true })
})
app.post('/look', (req, res) => {
  const { yaw, pitch } = req.body
  bot.look(yaw, pitch, true)
  res.json({ ok: true })
})
app.post('/mine', async (req, res) => {
  const { x, y, z } = req.body
  const block = bot.blockAt({ x, y, z })
  if (!block) return res.status(400).json({ error: 'No block there' })

  try {
    await bot.dig(block)
    res.json({ ok: true })
  } catch (e) {
    res.status(500).json({ error: e.message })
  }
})
app.post('/place', async (req, res) => {
  const { x, y, z } = req.body
  const referenceBlock = bot.blockAt(bot.entity.position.offset(0, -1, 0))
  if (!referenceBlock) return res.status(400).json({ error: 'No
reference block' })

  try {
    await bot.placeBlock(referenceBlock, { x, y, z })
    res.json({ ok: true })
  } catch (e) {
    res.status(500).json({ error: e.message })
  }
})

app.get('/state', (req, res) => {
  const pos = bot.entity.position
  res.json({
    position: { x: pos.x, y: pos.y, z: pos.z },
    health: bot.health,
    food: bot.food
  })
})

app.listen(3000, () => {
  console.log('Agent API listening on port 3000')
})

