package com.don.agentmod.api;

import fi.iki.elonen.NanoHTTPD;
import net.minecraft.server.MinecraftServer;
import net.minecraft.server.network.ServerPlayerEntity;

public class AgentApiServer extends NanoHTTPD {

    private static MinecraftServer server;

    public static void start() {
        try {
            AgentApiServer api = new AgentApiServer(8081);
            api.start(NanoHTTPD.SOCKET_READ_TIMEOUT, false);
            System.out.println("Agent API running on port 8081");
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public AgentApiServer(int port) {
        super(port);
    }

    @Override
    public Response serve(IHTTPSession session) {
        String uri = session.getUri();

        if (uri.equals("/move")) {
            return MoveAction.handle(session, server);
        }
        if (uri.equals("/mine")) {
            return MineAction.handle(session, server);
        }
        if (uri.equals("/place")) {
            return BuildAction.handle(session, server);
        }
        if (uri.equals("/look")) {
            return LookAction.handle(session, server);
        }

        return newFixedLengthResponse("Unknown endpoint");
    }

    public static void setServer(MinecraftServer s) {
        server = s;
    }
}

