package com.don.agentmod.actions;

import fi.iki.elonen.NanoHTTPD;
import net.minecraft.server.MinecraftServer;
import net.minecraft.server.network.ServerPlayerEntity;

public class MoveAction {

    public static NanoHTTPD.Response handle(NanoHTTPD.IHTTPSession
session, MinecraftServer server) {
        String direction = session.getParms().get("direction");
        ServerPlayerEntity agent =
server.getPlayerManager().getPlayer("AgentBot");

        if (agent == null) {
            return NanoHTTPD.newFixedLengthResponse("Agent not found");
        }

        switch (direction) {
            case "forward":
                agent.updatePosition(agent.getX() + 1, agent.getY(),
agent.getZ());
                break;
            case "back":
                agent.updatePosition(agent.getX() - 1, agent.getY(),
agent.getZ());
                break;
            case "left":
                agent.updatePosition(agent.getX(), agent.getY(),
agent.getZ() + 1);
                break;
            case "right":
                agent.updatePosition(agent.getX(), agent.getY(),
agent.getZ() - 1);
                break;
        }

        return NanoHTTPD.newFixedLengthResponse("OK");
    }
}

