package com.don.agentbridge.api;

import fi.iki.elonen.NanoHTTPD;
import org.bukkit.Bukkit;
import org.bukkit.entity.Player;
import org.bukkit.plugin.Plugin;

public class ApiServer extends NanoHTTPD {

    private static Plugin plugin;

    public static void start(Plugin p) {
        plugin = p;
        try {
            ApiServer server = new ApiServer(8082);
            server.start(NanoHTTPD.SOCKET_READ_TIMEOUT, false);
            plugin.getLogger().info("Agent API running on port 8082");
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public ApiServer(int port) {
        super(port);
    }

    @Override
    public Response serve(IHTTPSession session) {
        String uri = session.getUri();

        switch (uri) {
            case "/move":
                return MoveAction.handle(session, plugin);
            case "/mine":
                return MineAction.handle(session, plugin);
            case "/place":
                return PlaceAction.handle(session, plugin);
            case "/look":
                return LookAction.handle(session, plugin);
            case "/pathfind":
                return PathfindAction.handle(session, plugin);
            default:
                return newFixedLengthResponse("Unknown endpoint");
        }
    }
}

