package com.don.agentbridge.actions;

import fi.iki.elonen.NanoHTTPD;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.entity.Player;
import org.bukkit.plugin.Plugin;

public class PathfindAction {

    public static NanoHTTPD.Response handle(NanoHTTPD.IHTTPSession
session, Plugin plugin) {
        Player agent = Bukkit.getPlayer("AgentBot");
        if (agent == null)
            return NanoHTTPD.newFixedLengthResponse("Agent not online");

        int x = Integer.parseInt(session.getParms().get("x"));
        int y = Integer.parseInt(session.getParms().get("y"));
        int z = Integer.parseInt(session.getParms().get("z"));

        Location target = new Location(agent.getWorld(), x, y, z);

        Bukkit.getScheduler().runTask(plugin, () -> {
            agent.teleport(target);
        });

        return NanoHTTPD.newFixedLengthResponse("OK");
    }
}

