def move_towards(px, py, pz, tx, ty, tz):
    dx = tx - px
    dz = tz - pz

    if dx > 0:
        requests.get(f"{BASE}/move", params={"direction": "forward"})
    elif dx < 0:
        requests.get(f"{BASE}/move", params={"direction": "back"})

    if dz > 0:
        requests.get(f"{BASE}/move", params={"direction": "right"})
    elif dz < 0:
        requests.get(f"{BASE}/move", params={"direction": "left"})

    time.sleep(0.2)

