import requests
import time

BASE = "http://localhost:8082"

class Navigator:
    def __init__(self):
        pass

    def get_position(self):
        r = requests.get(f"{BASE}/state")
        pos = r.json()["position"]
        return pos["x"], pos["y"], pos["z"]

    def goto(self, tx, ty, tz):
        px, py, pz = self.get_position()

        start = Node(int(px), int(py), int(pz), 0, 0)
        goal = Node(int(tx), int(ty), int(tz), 0, 0)

        path = astar(start, goal, is_walkable)

        if not path:
            print("No path found")
            return False

        for (x, y, z) in path:
            move_towards(px, py, pz, x, y, z)
            px, py, pz = x, y, z
            time.sleep(0.1)

        return True

