from world_adapter import get_block

class MineTask(BaseTask):
    def plan(self):
        self.target = self.params["target"]
        self.nav = Navigator()
        self.miner = Miner()

        # Find a block of the target type nearby
        for x in range(-20, 21):
            for y in range(-5, 6):
                for z in range(-20, 21):
                    bx = self.agent.x + x
                    by = self.agent.y + y
                    bz = self.agent.z + z
                    if get_block(bx, by, bz) == self.target:
                        self.block_pos = (bx, by, bz)
                        return True

        self.fail("No target block found")
        return False

    def step(self):
        if self.status == "failed":
            return

        bx, by, bz = self.block_pos

        # Move to block
        if not self.nav.goto(bx, by, bz):
            self.fail("Navigation failed")
            return

        # Mine block
        self.miner.mine_area(bx, by, bz, bx+1, by+1, bz+1)

        self.complete()

