from task_planner.tasks.mine_task import MineTask
from task_planner.tasks.build_task import BuildTask
from task_planner.tasks.explore_task import ExploreTask

TASK_MAP = {
    "mine": MineTask,
    "build": BuildTask,
    "explore": ExploreTask
}

class TaskPlanner:
    def __init__(self, agent):
        self.agent = agent
        self.current_task = None

    def assign(self, task_type, params=None):
        task_class = TASK_MAP.get(task_type)
        if not task_class:
            raise Exception("Unknown task type")

        self.current_task = task_class(self.agent, params)
        if not self.current_task.plan():
            print("Task planning failed:", self.current_task.reason)
            self.current_task = None

    def tick(self):
        if not self.current_task:
            return

        if not self.current_task.is_complete():
            self.current_task.step()
        else:
            print("Task complete:", self.current_task)
            self.current_task = None

