from multi_agent.blackboard import Blackboard
from multi_agent.messages import MessageBus
from multi_agent.roles import Role

class Coordinator:
    def __init__(self, team):
        self.team = team
        self.blackboard = Blackboard()
        self.messages = MessageBus()

    def assign_roles(self):
        for i, agent in enumerate(self.team.members):
            if i == 0:
                self.team.roles[agent.id] = Role.MINER
            elif i == 1:
                self.team.roles[agent.id] = Role.BUILDER
            else:
                self.team.roles[agent.id] = Role.SCOUT

    def broadcast(self, msg):
        for agent in self.team.members:
            self.messages.send(agent, msg)

    def tick(self):
        # Example: share discovered resources
        ore_locations = self.blackboard.get("ores", [])
        if ore_locations:
            self.broadcast({"type": "resource", "data": ore_locations})

