import requests
from farming.crop_data import CROPS

BASE = "http://localhost:8082"

class CropDetector:
    def __init__(self):
        pass

    def get_block(self, x, y, z):
        r = requests.get(f"{BASE}/block", params={"x": x, "y": y, "z": z})
        return r.json()

    def find_mature_crops(self, radius=20):
        mature = []
        for x in range(-radius, radius+1):
            for z in range(-radius, radius+1):
                for y in range(60, 75):  # farmland range
                    block = self.get_block(x, y, z)
                    if block["type"] in CROPS:
                        crop = CROPS[block["type"]]
                        if block["age"] >= crop["mature_age"]:
                            mature.append({"pos": (x, y, z), "crop":
block["type"]})
        return mature

