from task_planner.tasks.base_task import BaseTask
from navigator import Navigator
from farming.detector import CropDetector
from farming.harvester import Harvester
from farming.planter import Planter

class FarmTask(BaseTask):
    def plan(self):
        self.detector = CropDetector()
        self.harvester = Harvester()
        self.planter = Planter()
        self.nav = Navigator()

        self.targets = self.detector.find_mature_crops()
        if not self.targets:
            self.fail("No mature crops found")
            return False

        return True

    def step(self):
        if not self.targets:
            self.complete()
            return

        target = self.targets.pop(0)
        x, y, z = target["pos"]
        crop_type = target["crop"]

        # Move to crop
        if not self.nav.goto(x, y, z):
            self.fail("Navigation failed")
            return

        # Harvest
        self.harvester.harvest(x, y, z)

        # Replant
        self.planter.plant(x, y, z, crop_type)

