class CraftingTask(BaseTask):
    def plan(self):
        self.item = self.params["item"]
        self.nav = Navigator()
        self.crafter = Crafter()
        self.inv = Inventory()

        # Check if we have materials
        recipe = self.params["recipe"]
        for row in recipe:
            for ingredient in row:
                if ingredient and not self.inv.has(ingredient):
                    self.fail("Missing materials")
                    return False

        return True

    def step(self):
        # Move to crafting table
        tx, ty, tz = self.params["table_pos"]
        if not self.nav.goto(tx, ty, tz):
            self.fail("Navigation failed")
            return

        # Craft item
        self.crafter.craft(self.item)

        self.complete()

