class RepairTask(BaseTask):
    def plan(self):
        self.blueprint = self.params["blueprint"]
        self.origin = self.params["origin"]
        self.nav = Navigator()
        self.builder = Builder()

        self.to_fix = []
        for block in self.blueprint["blocks"]:
            x = self.origin[0] + block["x"]
            y = self.origin[1] + block["y"]
            z = self.origin[2] + block["z"]

            current = get_block(x, y, z)
            if current["type"] != block["type"]:
                self.to_fix.append((x, y, z, block["type"]))

        return True

    def step(self):
        if not self.to_fix:
            self.complete()
            return

        x, y, z, t = self.to_fix.pop(0)

        if not self.nav.goto(x, y, z):
            self.fail("Navigation failed")
            return

        self.builder.build_wall(x, y, z, 1, 1, t)

