        blocks = self.blueprint["blocks"]
        chunk_size = len(blocks) // len(self.team.members)

        assignments = []
        for i, agent in enumerate(self.team.members):
            start = i * chunk_size
            end = (i + 1) * chunk_size if i < len(self.team.members) -
1 else len(blocks)
            assignments.append((agent, blocks[start:end]))

        return assignments

