🧩 2. Formations (Line, Wedge, Circle, Column)

formations.py

class Formation:
    @staticmethod
    def line(center, count, spacing=2):
        cx, cy, cz = center
        return [(cx + (i - count//2) * spacing, cy, cz) for i in range(count)]

    @staticmethod
    def wedge(center, count, spacing=2):
        cx, cy, cz = center
        positions = []
        for i in range(count):
            offset = i - count//2
            positions.append((cx + offset * spacing, cy, cz +
abs(offset) * spacing))
        return positions

    @staticmethod
    def circle(center, count, radius=4):
        import math
        cx, cy, cz = center
        return [
            (cx + radius * math.cos(2*math.pi*i/count),
             cy,
             cz + radius * math.sin(2*math.pi*i/count))
            for i in range(count)
        ]

Your squad can now *take formation*.
