class Maneuvers:
    @staticmethod
    def flank(enemy_pos, count):
        ex, ey, ez = enemy_pos
        return [
            (ex + 4, ey, ez + 2),
            (ex - 4, ey, ez + 2),
            (ex + 4, ey, ez - 2),
            (ex - 4, ey, ez - 2)
        ][:count]

    @staticmethod
    def surround(enemy_pos, count):
        import math
        ex, ey, ez = enemy_pos
        radius = 5
        return [
            (ex + radius * math.cos(2*math.pi*i/count),
             ey,
             ez + radius * math.sin(2*math.pi*i/count))
            for i in range(count)
        ]

    @staticmethod
    def retreat(center, distance=10):
        cx, cy, cz = center
        return (cx, cy, cz - distance)

