class ThreatMap:
    def __init__(self):
        self.map = {}

    def update(self, enemies):
        self.map.clear()
        for e in enemies:
            pos = (e["x"], e["y"], e["z"])
            self.map[pos] = self.map.get(pos, 0) + 1

    def highest_threat(self):
        if not self.map:
            return None
        return max(self.map.items(), key=lambda x: x[1])[0]

