class SquadCommander:
    def __init__(self, team, coordinator):
        self.team = team
        self.coordinator = coordinator
        self.threat_map = ThreatMap()

    def update_threats(self, enemies):
        self.threat_map.update(enemies)

    def choose_strategy(self):
        threat = self.threat_map.highest_threat()
        if not threat:
            return "patrol", None

        # Simple logic — can be soul‑driven later
        if len(self.team.members) >= 4:
            return "surround", threat
        else:
            return "flank", threat

    def assign_orders(self, strategy, target):
        agents = self.team.members

        if strategy == "surround":
            positions = Maneuvers.surround(target, len(agents))
        elif strategy == "flank":
            positions = Maneuvers.flank(target, len(agents))
        else:
            positions = Formation.line(target, len(agents))

        assignments = Positioning.assign_positions(agents, positions)

        for agent in agents:
            self.coordinator.messages.send(agent, {
                "type": "tactical_move",
                "pos": assignments[agent.id]
            })

