        if "build_bias" in mods:
            weights["build"] += mods["build_bias"]

        if "combat_bias" in mods:
            weights["combat"] += mods["combat_bias"]

        if "resource_bias" in mods:
            weights["mine"] += mods["resource_bias"]

        # Mood effects
