from economy.trade_offer import TradeOffer

class TraderAI:
    def __init__(self, agent, market, currency):
        self.agent = agent
        self.market = market
        self.currency = currency

    def create_offer(self, item, quantity):
        price =
self.agent.personality.get_modifiers().get("resource_bias", 0) + 5
        offer = TradeOffer(self.agent, item, price, quantity)
        self.market.add_offer(offer)

    def buy(self, item, quantity):
        offer = self.market.find_best_price(item)
        if not offer:
            return False

        total_cost = offer.price * quantity
        if self.currency.get(self.agent.id) < total_cost:
            return False

        # Transfer currency
        self.currency.subtract(self.agent.id, total_cost)
        self.currency.add(offer.seller.id, total_cost)

        # Transfer items
        offer.seller.inventory.remove(item, quantity)
        self.agent.inventory.add(item, quantity)

        offer.quantity -= quantity
        return True

Agents can now *buy and sell*.
