import requests

BASE = "http://localhost:8082"

class TerrainScanner:
    def __init__(self):
        pass

    def get_block(self, x, y, z):
        return requests.get(f"{BASE}/block", params={"x": x, "y": y,
"z": z}).json()

    def scan_area(self, x1, z1, x2, z2):
        area = {}
        for x in range(x1, x2+1):
            for z in range(z1, z2+1):
                # find highest solid block
                for y in range(200, 0, -1):
                    block = self.get_block(x, y, z)
                    if block["type"] != "AIR":
                        area[(x, z)] = y
                        break
        return area

This gives you a *heightmap* of the terrain.
