class HeightmapAnalyzer:
    def __init__(self, heightmap):
        self.heightmap = heightmap

    def average_height(self):
        return sum(self.heightmap.values()) / len(self.heightmap)

    def find_outliers(self, threshold=2):
        avg = self.average_height()
        return {
            pos: h for pos, h in self.heightmap.items()
            if abs(h - avg) > threshold
        }

This identifies *bumps*, *holes*, and *uneven terrain*.
