from task_planner.tasks.base_task import BaseTask
from terraforming.scanner import TerrainScanner
from terraforming.heightmap import HeightmapAnalyzer
from terraforming.flattener import Flattener
from terraforming.clearer import Clearer
from navigator import Navigator

class TerraformTask(BaseTask):
    def plan(self):
        self.area = self.params["area"]
        self.target_height = self.params["target_height"]

        self.scanner = TerrainScanner()
        self.nav = Navigator()
        self.flattener = Flattener()
        self.clearer = Clearer()

        x1, z1, x2, z2 = self.area
        self.heightmap = self.scanner.scan_area(x1, z1, x2, z2)
        self.analyzer = HeightmapAnalyzer(self.heightmap)

        self.outliers = self.analyzer.find_outliers()
        return True

    def step(self):
        if not self.outliers:
            self.complete()
            return

        (x, z), h = self.outliers.popitem()

        # Move to location
        if not self.nav.goto(x, h, z):
            self.fail("Navigation failed")
            return

        # Clear block
        self.clearer.clear_block(x, h, z)

        # Flatten
        self.flattener.flatten_to(x, h, z, self.target_height)

Agents can now *flatten entire regions*.
