class TerraformCoordinator:
    def __init__(self, team, area, target_height):
        self.team = team
        self.area = area
        self.target_height = target_height

    def divide_area(self):
        x1, z1, x2, z2 = self.area
        width = (x2 - x1) // len(self.team.members)

        assignments = []
        for i, agent in enumerate(self.team.members):
            ax1 = x1 + i * width
            ax2 = x1 + (i+1) * width
            assignments.append((agent, (ax1, z1, ax2, z2)))

        return assignments

