from task_planner.tasks.base_task import BaseTask
from navigator import Navigator

class HaulingTask(BaseTask):
    def plan(self):
        self.item = self.params["item"]
        self.count = self.params["count"]
        self.from_pos = self.params["from"]
        self.to_pos = self.params["to"]

        self.nav = Navigator()
        return True

    def step(self):
        # Go to pickup
        if not self.nav.goto(*self.from_pos):
            self.fail("Navigation to pickup failed")
            return

        # Pickup item
        self.agent.inventory.add(self.item, self.count)

        # Go to dropoff
        if not self.nav.goto(*self.to_pos):
            self.fail("Navigation to dropoff failed")
            return

        # Drop item
        self.agent.inventory.remove(self.item, self.count)

        self.complete()

