class SupplyManager:
    def __init__(self, storages):
        self.storages = storages

    def find_item(self, item):
        for s in self.storages:
            if s.has(item):
                return s
        return None

    def request_supply(self, item, count, target_pos):
        source = self.find_item(item)
        if not source:
            return None

        return {
            "item": item,
            "count": count,
            "from": source.pos,
            "to": target_pos
        }

