class LogisticsCoordinator:
    def __init__(self, team, supply_manager):
        self.team = team
        self.supply_manager = supply_manager
        self.queue = []

    def request(self, item, count, target_pos):
        job = self.supply_manager.request_supply(item, count, target_pos)
        if job:
            self.queue.append(job)

    def tick(self):
        if not self.queue:
            return

        job = self.queue.pop(0)
        agent = min(self.team.members, key=lambda a: a.distance_to(job["from"]))

        agent.planner.assign("haul", job)

