class RelationshipGraph:
    def __init__(self):
        self.edges = {}  # (a_id, b_id) -> score

    def modify(self, a, b, delta):
        key = (a.id, b.id)
        self.edges[key] = max(-10, min(10, self.edges.get(key, 0) + delta))

    def get(self, a, b):
        return self.edges.get((a.id, b.id), 0)

    def strongest_bond(self, agent):
        bonds = {k: v for (x, k), v in self.edges.items() if x == agent.id}
        if not bonds:
            return None
        return max(bonds.items(), key=lambda x: x[1])

