    def worsen(self, a, b, amount=1):
        self.graph.modify(a, b, -amount)
        self.graph.modify(b, a, -amount)

    def get_relationship(self, a, b):
        score = self.graph.get(a, b)
        if score > 5:
            return "friend"
        if score < -5:
            return "enemy"
        if score > 2:
            return "ally"
        if score < -2:
            return "rival"
        return "neutral"

