class RoadNetwork:
    def __init__(self):
        self.paths = []

    def connect(self, a, b):
        # Simple straight-line road
        path = []
        x1, y1, z1 = a
        x2, y2, z2 = b

        dx = 1 if x2 > x1 else -1
        dz = 1 if z2 > z1 else -1

        for x in range(x1, x2, dx):
            path.append((x, y1, z1))
        for z in range(z1, z2, dz):
            path.append((x2, y1, z))

        self.paths.append(path)
        return path

