class ElectionSystem:
    def __init__(self, town):
        self.town = town

    def hold_election(self):
        candidates = self.town.population
        votes = {}

        for voter in self.town.population:
            # Vote based on social relationships + reputation
            scores = {
                c.id: voter.memory.social.get_opinion(c.id) +
                      self.town.reputation.get(c.id)
                for c in candidates
            }
            choice = max(scores, key=scores.get)
            votes[choice] = votes.get(choice, 0) + 1

        winner_id = max(votes, key=votes.get)
        self.town.government.leader = self._find_agent(winner_id)

    def _find_agent(self, agent_id):
        for a in self.town.population:
            if a.id == agent_id:
                return a

