import random
from world_events.event_types import EVENT_TYPES

class EventGenerator:
    def __init__(self):
        self.weights = {
            "natural_disaster": 1,
            "environmental": 2,
            "economic": 1,
            "social": 2,
            "hostile": 1,
            "mystical": 0.5
        }

    def generate(self):
        category = random.choices(
            list(self.weights.keys()),
            weights=self.weights.values()
        )[0]
        event = random.choice(EVENT_TYPES[category])
        return category, event

