        self.religions = religions

    def check_conflict(self):
        # Simple: conflicting values
        for r1 in self.religions:
            for r2 in self.religions:
                if r1 is not r2:
                    if set(r1.values).isdisjoint(r2.values):
                        return (r1, r2)
        return None

