class Researcher:
    def __init__(self, agent, tree):
        self.agent = agent
        self.tree = tree
        self.progress = {}

    def work_on(self, node_name):
        node = self.tree.nodes[node_name]
        self.progress[node_name] = self.progress.get(node_name, 0) + 1

        if self.progress[node_name] >= node.cost:
            node.completed = True
            return node.unlocks
        return None

