class InheritanceSystem:
    def distribute(self, deceased, town):
        heirs = town.family_tree.children.get(deceased.id, [])
        if not heirs:
            return

        # Simple: oldest child inherits everything
        heir = max(heirs, key=lambda cid: town.get_agent(cid).age)

        heir.inventory.items.update(deceased.inventory.items)
        heir.reputation += deceased.reputation * 0.2

