class Migration:
    def migrate(self, species, from_biome, to_biome):
        if to_biome.fertility > from_biome.fertility:
            amount = species.population * 0.1
            species.population -= amount
            # clone species into new biome
            new_species = Species(species.name, species.diet,
species.reproduction_rate, species.aggression)
            new_species.population = amount
            to_biome.species.append(new_species)

