from agent_factory.registry import AgentRegistry
from agent_factory.traits import BRAVE_PACK, DIPLOMAT_PACK, PRIEST_PACK
from agent_factory.roles import WORKER_ROLE, MAYOR_ROLE, PRIEST_ROLE

class AgentFactory:
    def __init__(self, world):
        self.world = world
        self.registry = AgentRegistry()

    def create_agent(self, blueprint_key, town, extra_traits=None,
extra_roles=None):
        bp = self.registry.get_blueprint(blueprint_key)

        agent = Agent()  # your existing Agent class
        agent.stats.update(bp.base_stats)
        agent.personality.traits.extend(bp.default_traits)

        if extra_traits:
            for pack in extra_traits:
                agent.personality.traits.extend(pack.traits)

        roles = bp.default_roles[:]
        if extra_roles:
            roles.extend(extra_roles)

        agent.roles = roles
        agent.town = town
        agent.world = self.world

        town.population.append(agent)
        self.world.agents.append(agent)

        return agent

    def create_mayor(self, town):
        agent = self.create_agent(
            "citizen",
            town,
            extra_traits=[DIPLOMAT_PACK],
            extra_roles=["mayor"]
        )
        town.government.leader = agent
        return agent

    def create_priest(self, town, religion):
        agent = self.create_agent(
            "citizen",
            town,
            extra_traits=[PRIEST_PACK],
            extra_roles=["priest"]
        )
        religion.priesthood.appoint(agent)
        return agent

    def create_guard_squad(self, town, n=5):
        guards = []
        for _ in range(n):
            g = self.create_agent("guard", town, extra_traits=[BRAVE_PACK])
            town.enforcement.assign_guard(g)
            guards.append(g)
        return guards

