class SafetyLayer:
    def filter(self, intents):
        safe = []
        for agent, intent in intents:
            if self._valid(agent, intent):
                safe.append((agent, intent))
        return safe

    def _valid(self, agent, intent):
        if intent.type == "cast_spell" and agent.mana < intent.cost:
            return False
        if intent.type == "attack" and agent.status == "jailed":
            return False
        return True

