# agent_factory.py

class AgentFactory:
    def __init__(self, world):
        self.world = world

    def create(self, blueprint, town=None, traits=None, roles=None):
        agent = Agent()

        # Base stats
        agent.stats = blueprint.base_stats.copy()

        # Personality
        agent.personality.traits = list(blueprint.default_traits)
        if traits:
            for t in traits:
                agent.personality.traits.extend(t.traits)

        # Roles
        agent.roles = list(blueprint.default_roles)
        if roles:
            agent.roles.extend(roles)

        # World placement
        agent.world = self.world
        if town:
            agent.town = town
            town.population.append(agent)

        self.world.agents.append(agent)
        return agent

This is the *core constructor*.
Everything else (skills, planners, memory, etc.) attaches modularly.
