class Market:
    def __init__(self):
        self.prices = {}
        self.inventory = {}

    def buy(self, resource, amount, price):
        self.inventory[resource] = self.inventory.get(resource, 0) + amount
        self.prices[resource] = price

    def sell(self, resource, amount):
        if self.inventory.get(resource, 0) < amount:
            return False
        self.inventory[resource] -= amount
        return True

